// ── ブランドロゴ ──
// マークはインラインSVG(XORで交差を白抜き)、ロゴタイプ「ミチノリ」はdata URI。
// バイナリ資産を持たずテキストのみで完結させ、どの配信経路でも壊れない。
import { useRef } from "react";

let logoSeq = 0;
export function LogoMark({ size = 32 }: { size?: number }) {
  const idsRef = useRef<Record<string, string> | null>(null);
  if (!idsRef.current) {
    const n = ++logoSeq;
    idsRef.current = { k:`k${n}`, b:`b${n}`, l:`l${n}`, mk:`mk${n}`, mb:`mb${n}`, ml:`ml${n}` };
  }
  const i = idsRef.current;
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" aria-hidden="true" style={{ display: "block", flex: "none" }}>
      <defs>
        <ellipse id={i.k} cx="36.5" cy="31" rx="15" ry="20.5" transform="rotate(24 36.5 31)" />
        <ellipse id={i.b} cx="53" cy="52.5" rx="37" ry="19.5" transform="rotate(-29 53 52.5)" />
        <circle id={i.l} cx="66.5" cy="64" r="12" />
        <mask id={i.mk}><rect x="-10" y="-10" width="120" height="120" fill="#fff" /><use href={`#${i.b}`} fill="#000" /><use href={`#${i.l}`} fill="#000" /></mask>
        <mask id={i.mb}><rect x="-10" y="-10" width="120" height="120" fill="#fff" /><use href={`#${i.k}`} fill="#000" /><use href={`#${i.l}`} fill="#000" /></mask>
        <mask id={i.ml}><rect x="-10" y="-10" width="120" height="120" fill="#fff" /><use href={`#${i.k}`} fill="#000" /><use href={`#${i.b}`} fill="#000" /></mask>
      </defs>
      <use href={`#${i.k}`} fill="#111111" mask={`url(#${i.mk})`} />
      <use href={`#${i.b}`} fill="#2000FF" mask={`url(#${i.mb})`} />
      <use href={`#${i.l}`} fill="#C9C6F0" mask={`url(#${i.ml})`} />
    </svg>
  );
}

export const TYPE_SRC =
  "data:image/png;base64,";
